const telemetry = $('Combine Diagnostics and Telemetry').item.json;
const response = $json;

return {
  json: {
    ...telemetry,
    retry_status_code: response.statusCode || 0,
    retry_outcome: (response.statusCode >= 200 && response.statusCode < 300) ? 'queued' : 'failed',
    retry_response_body: response.body || {}
  }
};

const retryCount = $json.retry_count || 0;
const baseSeconds = 30;
const backoffSeconds = Math.min(baseSeconds * Math.pow(4, retryCount), 480);

return {
  json: {
    ...$json,
    backoff_seconds: backoffSeconds
  }
};

