const telemetry = $('Extract Error Details').item.json;

return {
  json: {
    ...telemetry,
    ai_category: 'logic',
    ai_confidence: 0,
    ai_reasoning: 'AI diagnostics step itself failed (LLM call or output parsing error) - this is an unclassified failure that needs manual review.',
    ai_remediation: 'Review the original error_message and error_stack directly; automated classification was unavailable for this incident.',
    diagnostics_failed: true
  }
};

const diagnostics = $json.output || {};
const telemetry = $('Extract Error Details').item.json;


const staticData = $getWorkflowStaticData('global');
if (!staticData.retryCounters) staticData.retryCounters = {};

const lineageKey = telemetry.retry_of || telemetry.execution_id || 'unknown';
const MAX_RETRIES = 3;
const ENTRY_TTL_MS = 24 * 60 * 60 * 1000; 
const now = Date.now();


for (const key of Object.keys(staticData.retryCounters)) {
  const entry = staticData.retryCounters[key];
  if (entry && now - entry.lastSeen > ENTRY_TTL_MS) {
    delete staticData.retryCounters[key];
  }
}

if (!telemetry.is_retry) {

  staticData.retryCounters[lineageKey] = { count: 0, lastSeen: now };
} else {
  const existing = staticData.retryCounters[lineageKey] || { count: 0, lastSeen: now };

  existing.count = Math.min(existing.count + 1, MAX_RETRIES);
  existing.lastSeen = now;
  staticData.retryCounters[lineageKey] = existing;
}

const retryCount = staticData.retryCounters[lineageKey].count;
const retryExhausted = retryCount >= MAX_RETRIES;

return {
  json: {
    ...telemetry,
    lineage_key: lineageKey,
    ai_category: diagnostics.category || 'logic',
    ai_confidence: typeof diagnostics.confidence === 'number' ? diagnostics.confidence : 0,
    ai_reasoning: diagnostics.reasoning || 'No reasoning returned',
    ai_remediation: diagnostics.remediation || 'Manual review required',
    retry_count: retryCount,
    retry_exhausted: retryExhausted,
    eligible_for_retry:
      diagnostics.category === 'transient' &&
      (typeof diagnostics.confidence === 'number' ? diagnostics.confidence : 0) >= 0.6 &&
      !retryExhausted
  }
};

parameters.text:
=Classify this n8n workflow error.

Workflow: {{ $json.workflow_name }}
Failing node: {{ $json.failing_node }}
HTTP status (if detected): {{ $json.http_status }}
Error message: {{ $json.error_message }}
Stack trace (truncated):
{{ $json.error_stack.slice(0, 1500) }}

Return ONLY a JSON object, no markdown fences, no preamble, in exactly this shape:
{
  "category": "transient" | "logic",
  "confidence": 0.0-1.0,
  "reasoning": "one sentence explanation",
  "remediation": "one sentence suggested fix"
}

Classification rules:
- "transient": network timeouts, 429/502/503/504 status codes, rate limits, connection resets, temporary upstream outages. These are safe to retry automatically.
- "logic": TypeError, undefined property access, missing JSON keys, schema mismatches, authentication failures (401/403), malformed input data, validation errors. These require human review and must never be auto-retried.

When in doubt, classify as "logic" so a human reviews it. Never guess in favor of "transient".

parameters.jsCode:
const data = $json;

const execution = data.execution || {};
const workflow = data.workflow || {};
const trigger = data.trigger || {};

const errorSource = execution.error || (trigger && trigger.error) || {};

const failingNodeName =
  execution.lastNodeExecuted ||
  (errorSource.node && errorSource.node.name) ||
  'Unknown Node';

const stack = errorSource.stack || '';
const message = errorSource.message || 'No error message provided';

const statusMatch = (message + ' ' + stack).match(/\b(4\d{2}|5\d{2})\b/);
const httpStatus = statusMatch ? parseInt(statusMatch[1], 10) : null;

const executionId = execution.id || null;
const executionUrl = execution.url || null;
const isRetry = !!execution.retryOf;

return {
  json: {
    execution_id: executionId,
    execution_url: executionUrl,
    is_retry: isRetry,
    retry_of: execution.retryOf || null,
    workflow_id: workflow.id || null,
    workflow_name: workflow.name || 'Unknown Workflow',
    failing_node: failingNodeName,
    error_message: message,
    error_stack: stack,
    http_status: httpStatus,
    failed_at: new Date().toISOString(),
    raw_mode: execution.mode || 'unknown'
  }
};
